// Parse verification output and format for email
const sshOutput = $input.first().json;
const stdout = sshOutput.stdout || '';
const stderr = sshOutput.stderr || '';
const exitCode = sshOutput.code || 0;

const timestamp = new Date().toLocaleString('en-US', { 
  timeZone: 'America/Chicago',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit',
  hour12: true
});

// Try to parse the JSON health report if available
let healthReport = null;
try {
  // Extract JSON from stdout if present
  const jsonMatch = stdout.match(/\{[\s\S]*"timestamp"[\s\S]*\}/m);
  if (jsonMatch) {
    healthReport = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  console.log('Could not parse health report JSON:', e);
}

// Format HTML email
let html = '<div style="font-family: Arial, sans-serif; max-width: 800px; margin: 0 auto;">';
html += '<div style="background-color: #dc3545; color: white; padding: 20px; border-radius: 5px 5px 0 0;">';
html += '<h1 style="margin: 0; font-size: 24px;">❌ Backup Verification Failed</h1>';
html += '</div>';

html += '<div style="background-color: #f8f9fa; padding: 20px; border: 1px solid #dee2e6; border-top: none;">';

// Verification Information
html += '<h2 style="color: #495057; font-size: 18px; margin-top: 0;">📋 Verification Details</h2>';
html += '<table style="width: 100%; border-collapse: collapse; margin-bottom: 20px;">';
html += `<tr><td style="padding: 8px; font-weight: bold; width: 150px;">Time:</td><td style="padding: 8px;">${timestamp} CST</td></tr>`;
html += `<tr><td style="padding: 8px; font-weight: bold;">Exit Code:</td><td style="padding: 8px;">${exitCode}</td></tr>`;
if (healthReport) {
  html += `<tr><td style="padding: 8px; font-weight: bold;">Overall Status:</td><td style="padding: 8px;">${healthReport.overall_status}</td></tr>`;
}
html += '</table>';

// Check Results (if health report available)
if (healthReport && healthReport.checks) {
  html += '<h2 style="color: #dc3545; font-size: 18px;">🔍 Failed Checks</h2>';
  html += '<table style="width: 100%; border-collapse: collapse; margin-bottom: 20px; border: 1px solid #dee2e6;">';
  html += '<tr style="background-color: #e9ecef;"><th style="padding: 10px; text-align: left;">Service</th><th style="padding: 10px; text-align: left;">Status</th><th style="padding: 10px; text-align: left;">Details</th></tr>';

  for (const [service, result] of Object.entries(healthReport.checks)) {
    const status = result.status || 'unknown';
    const details = result.details || 'No details';

    let statusColor = '#28a745'; // green
    let statusIcon = '✓';
    if (status === 'fail') {
      statusColor = '#dc3545'; // red
      statusIcon = '✗';
    } else if (status === 'warn') {
      statusColor = '#ffc107'; // yellow
      statusIcon = '⚠';
    } else if (status === 'skip') {
      statusColor = '#6c757d'; // gray
      statusIcon = 'ⓘ';
    }

    if (status === 'fail' || status === 'warn') {
      html += `<tr><td style="padding: 10px;">${service}</td><td style="padding: 10px; color: ${statusColor}; font-weight: bold;">${statusIcon} ${status}</td><td style="padding: 10px;">${details}</td></tr>`;
    }
  }

  html += '</table>';
}

// Full Output
html += '<h2 style="color: #495057; font-size: 18px;">📄 Verification Output</h2>';
html += '<pre style="background: #fff; padding: 15px; border: 1px solid #dee2e6; border-radius: 3px; overflow-x: auto; max-height: 400px; overflow-y: auto; font-size: 12px;">';
html += stdout;
html += '</pre>';

if (stderr) {
  html += '<h2 style="color: #dc3545; font-size: 18px; margin-top: 20px;">⚠️ Error Output</h2>';
  html += '<pre style="background: #fff3cd; padding: 15px; border: 1px solid #ffc107; border-radius: 3px; overflow-x: auto; max-height: 200px; overflow-y: auto; font-size: 12px;">';
  html += stderr;
  html += '</pre>';
}

html += '</div>';

// Footer
html += '<div style="background-color: #e9ecef; padding: 15px; text-align: center; border: 1px solid #dee2e6; border-top: none; border-radius: 0 0 5px 5px; color: #6c757d; font-size: 12px;">';
html += 'This is an automated backup verification notification';
html += '</div>';
html += '</div>';

// Return formatted data
return {
  json: {
    timestamp,
    exitCode,
    healthReport,
    emailSubject: '❌ Backup Verification Failed - ' + timestamp,
    emailBody: html
  }
};
